test('loads user', async () => {
  const fetchUser = jest.fn().mockResolvedValue({ id: 1, name: 'Ada' });
  const user = await fetchUser();
  expect(user.name).toBe('Ada');
});

@Test
public void testWithMock() {
    UserService mock = Mockito.mock(UserService.class);
    Mockito.when(mock.getUser(1)).thenReturn(new User(1, "Ada"));
    User user = mock.getUser(1);
    assertEquals("Ada", user.getName());
}

